mapper.select:
SELECT af.*, s.name AS student_name, s.student_no, ac.category_name
FROM archive_file af
LEFT JOIN student s ON af.student_id = s.pk_student
LEFT JOIN archive_category ac ON af.category_id = ac.pk_category


        AND af.student_id = #{studentId}


        AND af.category_id = #{categoryId}


        AND af.status = #{status}


ORDER BY af.upload_time DESC

mapper.update:
UPDATE archive_file
file_name = #{fileName}, description = #{description}, status = #{status},
WHERE pk_archive_file = #{pkArchiveFile}

UPDATE archive_file
SET status = #{status}, audit_user_id = #{auditUserId}, audit_time = NOW(), audit_remark = #{auditRemark}
WHERE pk_archive_file = #{pkArchiveFile}
